/// Verify archive-level GitHub artifact attestations **and** per-file attestations
/// for files extracted from an archive.
///
/// Some GitHub releases publish attestations for individual files inside an archive
/// (e.g. the extracted binary) rather than the archive blob itself. This function
/// handles both cases:
///
/// 1. First, attempt archive-level verification against the archive's SHA-256 digest.
/// 2. If that fails with "no attestations found" (the tool simply has no archive-level
///    attestation), extract the archive and check each extracted file.
/// 3. For each extracted file, query the GitHub attestation API and verify bundles.
///
/// Returns `Ok(true)` if any attestation (archive-level or per-file) verified
/// successfully. Returns `Ok(false)` only when extraction succeeds but no
/// attestations exist for the archive or any extracted file. Propagates errors for
/// anything else (extraction failure, API errors, verified-attestation-but-subject
/// mismatch).
///
/// `file_path` is the downloaded archive. `owner`/`repo` identify the GitHub source.
pub async fn verify_github_file_attestations(
    file_path: &Path,
    owner: &str,
    repo: &str,
    token: Option<&str>,
    signer_workflow: Option<&str>,
    api_url: Option<&str>,
) -> Result<bool> {
    let mut builder = AttestationClient::builder();
    if let Some(token) = token {
        builder = builder.github_token(token);
    }
    if let Some(api_url) = api_url {
        builder = builder.base_url(api_url);
    }
    let client = builder.build()?;

    // Step 1: Try archive-level verification first.
    let archive_digest = calculate_file_digest_async(file_path).await?;
    let archive_attestations = client
        .fetch_attestations(FetchParams {
            owner: owner.to_string(),
            repo: Some(format!("{owner}/{repo}")),
            digest: format!("sha256:{archive_digest}"),
            limit: 30,
            predicate_type: None,
        })
        .await?;

    if !archive_attestations.is_empty() {
        let artifact = tokio::fs::read(file_path).await?;
        let mut trust_roots = TrustRoots::default();
        let verified =
            verify_attestation_bundles(&archive_attestations, &artifact, signer_workflow, &mut trust_roots)
                .await;
        match verified {
            Ok(result) => return Ok(result),
            Err(AttestationError::Sigstore(msg)) if msg.contains("No certificate found") => {
                // This means the archive has attestations but they didn't verify
                // for this archive's bytes. Don't fall through to per-file.
                return Ok(false);
            }
            Err(e) => return Err(e),
        }
    }

    // Step 2: No archive-level attestations. Extract and check per-file.
    let tmp_dir = tempfile::tempdir()?;
    let format = TarFormat::from_file_name(
        file_path
            .file_name()
            .unwrap_or_default()
            .to_string_lossy()
            .as_ref(),
    );
    extract_archive(file_path, tmp_dir.path(), format)?;

    // Collect all regular file paths. Skip symlinks, directories, and device files.
    let mut files: Vec<_> = Vec::new();
    collect_files(tmp_dir.path(), &mut files)?;

    if files.is_empty() {
        return Err(AttestationError::Io(std::io::Error::new(
            std::io::ErrorKind::InvalidInput,
            "archive extracted but contains no regular files",
        )));
    }

    let mut errors = Vec::new();
    let mut found_nothing = true;

    for file_path in &files {
        let digest = calculate_file_digest_async(file_path).await?;
        let attestations = client
            .fetch_attestations(FetchParams {
                owner: owner.to_string(),
                repo: Some(format!("{owner}/{repo}")),
                digest: format!("sha256:{digest}"),
                limit: 30,
                predicate_type: None,
            })
            .await?;

        if attestations.is_empty() {
            // No attestations for this file — try the next one.
            found_nothing = false;
            continue;
        }

        found_nothing = false;
        let file_bytes = tokio::fs::read(file_path).await?;
