+            // Caller should have already checked archive-level verification.
+            Err(AttestationError::UnsupportedFormat(
+                "raw file has no archive structure to extract".to_string(),
+            ))
+        }
+    }
+}
+
+/// Recursively collect all regular file paths under `root`.
+fn collect_files(root: &Path, files: &mut Vec<std::path::PathBuf>) -> Result<()> {
+    if !root.is_dir() {
+        if root.is_file() {
+            files.push(root.to_path_buf());
+        }
+        return Ok(());
+    }
+    for entry in std::fs::read_dir(root).map_err(|e| {
+        AttestationError::Io(std::io::Error::new(std::io::ErrorKind::Other, e))
+    })? {
+        let entry = entry.map_err(|e| {
+            AttestationError::Io(std::io::Error::new(std::io::ErrorKind::Other, e))
+        })?;
+        let path = entry.path();
+        let file_type = entry.file_type().map_err(|e| {
+            AttestationError::Io(std::io::Error::new(std::io::ErrorKind::Other, e))
+        })?;
+        match file_type {
+            ft if ft.is_file() => {
+                files.push(path);
+            }
+            ft if ft.is_dir() => {
+                collect_files(&path, files)?;
+            }
+            _ => {
+                // Skip symlinks, block/char devices, sockets, pipes, etc.
+                // We only verify attestations for real files on disk.
+            }
+        }
+    }
+    Ok(())
+}
