/// Try to verify GitHub artifact attestations. Returns:
/// - Ok(true) if attestations exist and verified successfully
/// - Ok(false) if attestations exist but verification failed
/// - Err(NoAttestations) if no attestations found
/// - Err(Error) if an error occurred during verification
///
/// Tries archive-level attestation first, then falls back to per-file
/// attestation for archives where the release publishes attestations for
/// individual files inside the archive rather than the archive blob.
async fn try_verify_github_attestations(
    &self,
    ctx: &InstallContext,
    tv: &ToolVersion,
    file_path: &std::path::Path,
    api_url: &str,
) -> std::result::Result<bool, VerificationStatus> {
    ctx.pr
        .set_message("verify GitHub artifact attestations".to_string());

    // Parse owner/repo from the repo string
    let repo = self.repo();
    let parts: Vec<&str> = repo.split('/').collect();
    if parts.len() != 2 {
        return Err(VerificationStatus::Error(format!(
            "Invalid repo format: {repo}"
        )));
    }
    let (owner, repo_name) = (parts[0], parts[1]);

    // Step 1: Try archive-level verification (handles the common case where
    // the release publishes an attestation for the archive blob).
    match crate::github::sigstore::verify_attestation(
        file_path,
        owner,
        repo_name,
        None, // We don't know the expected workflow
        Some(api_url),
    )
    .await
    {
        Ok(verified) => {
            if verified {
                ctx.pr
                    .set_message("✓ GitHub artifact attestations verified".to_string());
                debug!("GitHub artifact attestations verified successfully for {tv}");
            }
            return Ok(verified);
        }
        Err(crate::github::sigstore::AttestationError::NoAttestations) => {
            // No archive-level attestations, fall through to per-file check.
            debug!("No archive-level attestations found for {tv}, trying per-file attestations");
        }
        Err(crate::github::sigstore::AttestationError::Verification(msg))
            if msg.contains("No certificate found") =>
        {
            // Archive-level attestations exist but don't verify for this archive.
            // This is a hard failure — attestations were found for the archive
            // but the archive bytes don't match. Don't fall through.
            return Ok(false);
        }
        Err(e) => return Err(VerificationStatus::Error(e.to_string())),
    }

    // Step 2: No archive-level attestations — try per-file verification.
    ctx.pr
        .set_message("verify GitHub per-file attestations".to_string());

    match crate::github::sigstore::verify_github_file_attestations(
        file_path,
        owner,
        repo_name,
        None,
        Some(api_url),
    )
    .await
    {
        Ok(verified) => {
            if verified {
                ctx.pr
                    .set_message("✓ GitHub per-file attestations verified".to_string());
                debug!("GitHub per-file attestations verified successfully for {tv}");
            }
            Ok(verified)
        }
        // No attestations found for archive or any extracted file
        Err(crate::github::sigstore::AttestationError::NoAttestations) => {
            Err(VerificationStatus::NoAttestations)
        }
        // Attestations exist for extracted files but verification failed
        Err(crate::github::sigstore::AttestationError::Verification(msg)) => {
            // Fail closed: attestations were found for extracted files but
            // none verified successfully.
            Err(VerificationStatus::Error(format!(
                "per-file attestation verification failed: {msg}"
            )))
        }
        Err(e) => Err(VerificationStatus::Error(e.to_string())),
    }
}

