/// Extract an archive to `dest`, handling tar, tar.gz, tar.bz2, tar.xz, zip, and 7z formats.
fn extract_archive(archive: &Path, dest: &Path, format: TarFormat) -> Result<()> {
    match format {
        TarFormat::Tar | TarFormat::TarGz | TarFormat::TarBz2 | TarFormat::TarXz => {
            let ar = open_tar(format, archive).map_err(|e| {
                AttestationError::Io(std::io::Error::new(
                    std::io::ErrorKind::InvalidInput,
                    format!("failed to open archive: {e}"),
                ))
            })?;
            let mut archive = tar::Archive::new(ar);
            // Safety: only extract regular files (skip symlinks, directories, etc.)
            // We only care about files that could contain binary content to verify.
            archive.set_preserve_mtime(false);
            archive
                .unpack(dest)
                .map_err(|e| AttestationError::Io(std::io::Error::new(std::io::ErrorKind::Other, e)))
        }
        TarFormat::Zip => {
            let file = std::fs::File::open(archive).map_err(|e| {
                AttestationError::Io(std::io::Error::new(
                    std::io::ErrorKind::InvalidInput,
                    format!("failed to open zip archive: {e}"),
                ))
            })?;
            let mut archive = zip::ZipArchive::new(file).map_err(|e| {
                AttestationError::Io(std::io::Error::new(
                    std::io::ErrorKind::InvalidInput,
                    format!("failed to parse zip archive: {e}"),
                ))
            })?;
            archive
                .extract(dest)
                .map_err(|e| AttestationError::Io(std::io::Error::new(std::io::ErrorKind::Other, e)))
        }
        TarFormat::SevenZip => {
            // 7z extraction not implemented in this crate
            Err(AttestationError::UnsupportedFormat(
                "7z archive format not supported for per-file attestation verification".to_string(),
            ))
        }
        TarFormat::Raw => {
            // No archive to extract — the "file" is the archive itself.
            // Caller should have already checked archive-level verification.
            Err(AttestationError::UnsupportedFormat(
                "raw file has no archive structure to extract".to_string(),
            ))
        }
    }
}

